function interpretLenormandCombination(card1, card2, lang = 'en') {
    const key1 = `${card1.en.name}-${card2.en.name}`;
    const key2 = `${card2.en.name}-${card1.en.name}`;
    const combo = lenormandCombinations[key1] || lenormandCombinations[key2];

    if (combo) return combo[lang];

    const kw1 = card1[lang].keywords || [];
    const kw2 = card2[lang].keywords || [];
    // Enhanced fallback with better context
    if (lang === 'vn') {
        return {
            meaning: `${card1.en.name} kết hợp với ${card2.en.name} cho thấy chủ đề ${kw1[0].toLowerCase()} đang giao thoa với ${kw2[0].toLowerCase()} trong tình huống của bạn. Đây là thông điệp thực tế về cách hai năng lượng này đang ảnh hưởng lẫn nhau trong cuộc sống hàng ngày.`,
            practical: `Quan sát cách ${kw1[0].toLowerCase()} và ${kw2[0].toLowerCase()} biểu hiện cụ thể trong tình huống hiện tại. Tìm sự kết nối thực tế, không phải biểu tượng.`
        };
    }
    return {
        meaning: `${card1.en.name} combined with ${card2.en.name} indicates that themes of ${kw1[0].toLowerCase()} are intersecting with ${kw2[0].toLowerCase()} in your situation. This is a practical message about how these two energies are influencing each other in your daily life.`,
        practical: `Observe how ${kw1[0].toLowerCase()} and ${kw2[0].toLowerCase()} manifest together in your current situation. Look for concrete, literal connections rather than symbolic ones.`
    };
}

function generateLenormandSynthesis(cards, spread, lang = 'en') {
    const count = cards.length;
    let html = '<div class="space-y-8 pb-12 animate-fade-in">';

    // OPENING
    html += `
        <div class="glass p-8 rounded-[2rem] border border-cyan-500/20 bg-cyan-950/5">
            <h4 class="text-xl font-bold text-cyan-400 mb-4 flex items-center gap-3">
                <i data-lucide="layout" class="w-6 h-6"></i>
                <span>${lang === 'en' ? 'Lenormand Narrative' : 'Tường Thuật Lenormand'}</span>
            </h4>
            <p class="text-slate-300 leading-relaxed italic">
                ${lang === 'en'
            ? "In Lenormand, cards work together to describe literal events. We don't look for symbols here, but for the actual story unfolding in your daily life."
            : "Trong Lenormand, các lá bài phối hợp để mô tả các sự kiện thực tế. Chúng ta không tìm biểu tượng trừu tượng, mà tìm câu chuyện đang diễn ra trong đời thực."}
            </p>
        </div>
    `;

    // COMBINATIONS GRID
    if (count > 1) {
        html += `<div class="grid gap-6">`;
        for (let i = 0; i < count - 1; i++) {
            const c1 = cards[i];
            const c2 = cards[i + 1];
            const combo = interpretLenormandCombination(c1, c2, lang);
            html += `
                <div class="glass p-6 rounded-3xl border border-indigo-500/20 bg-indigo-500/5">
                    <div class="flex items-center gap-4 mb-3 text-indigo-300 font-bold">
                        <span>${c1.en.name}</span>
                        <i data-lucide="arrow-right" class="w-4 h-4 opacity-50"></i>
                        <span>${c2.en.name}</span>
                    </div>
                    <p class="text-slate-200 text-sm mb-2">${combo.meaning}</p>
                    <div class="p-3 rounded-xl bg-slate-900/40 text-[13px] text-cyan-300 border border-cyan-500/10">
                        <span class="font-bold">💡 ${lang === 'en' ? 'Practical:' : 'Thực tế:'}</span> ${combo.practical}
                    </div>
                </div>
            `;
        }
        html += `</div>`;
    } else {
        // SINGLE CARD (Daily Draw)
        const card = cards[0];
        html += `
            <div class="glass p-8 rounded-[2rem] border border-amber-500/20 bg-amber-950/5 text-center">
                <div class="w-16 h-16 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto mb-6 border border-amber-500/30">
                    <i data-lucide="sparkles" class="w-8 h-8 text-amber-400"></i>
                </div>
                <h3 class="text-2xl font-bold text-amber-200 mb-4">${card.en.name}</h3>
                <p class="text-slate-200 text-lg mb-6">${card[lang].meaning}</p>
                <div class="flex flex-wrap justify-center gap-2">
                    ${card[lang].keywords.map(kw => `<span class="px-3 py-1 bg-amber-500/10 border border-amber-500/20 rounded-full text-xs text-amber-300 font-bold">#${kw}</span>`).join('')}
                </div>
            </div>
        `;
    }

    // TIMING & LITERALS
    html += `
        <div class="grid md:grid-cols-2 gap-8 mt-4">
            <div class="glass p-8 rounded-[2rem] border border-emerald-500/30 bg-emerald-950/10">
                <h4 class="text-lg font-bold text-emerald-400 mb-4 flex items-center gap-2">
                    <i data-lucide="clock" class="w-6 h-6"></i>
                    <span>${lang === 'en' ? 'Divine Timing' : 'Thời Điểm Thiên Định'}</span>
                </h4>
                <p class="text-slate-300 text-sm leading-relaxed">
                    ${analyzeTiming(cards, lang)}
                </p>
            </div>
            <div class="glass p-8 rounded-[2rem] border border-amber-500/30 bg-amber-950/10">
                <h4 class="text-lg font-bold text-amber-400 mb-4 flex items-center gap-2">
                    <i data-lucide="target" class="w-6 h-6"></i>
                    <span>${lang === 'en' ? 'Literal Manifestation' : 'Hiện Thực Hóa'}</span>
                </h4>
                <p class="text-slate-300 text-sm leading-relaxed">
                    ${analyzeLiterals(cards, lang)}
                </p>
            </div>
        </div>
    `;

    html += '</div>';
    if (typeof lucide !== 'undefined') setTimeout(() => lucide.createIcons(), 100);
    return html;
}

function analyzeTiming(cards, lang) {
    // Basic Lenormand timing logic
    const fast = ['Rider', 'Clover', 'Scythe', 'Whip', 'Birds'];
    const medium = ['Ship', 'Stork', 'Dog', 'Heart', 'Sun', 'Moon', 'Key', 'Fish', 'Bouquet'];
    const slow = ['House', 'Tree', 'Clouds', 'Snake', 'Coffin', 'Bear', 'Stars', 'Tower', 'Garden', 'Mountain', 'Crossroads', 'Mice', 'Ring', 'Book', 'Letter', 'Man', 'Woman', 'Lily', 'Anchor', 'Cross'];

    let fastCount = cards.filter(c => fast.includes(c.en.name)).length;
    let slowCount = cards.filter(c => slow.includes(c.en.name)).length;

    if (fastCount > slowCount) {
        return lang === 'en' ? "Events will unfold <strong>very quickly</strong>. Look for developments within days, or even hours. The energy is rushing toward you." : "Sự kiện sẽ diễn ra <strong>rất nhanh</strong>. Hãy chờ đợi các diễn biến trong vòng vài ngày, thậm chí vài giờ. Năng lượng đang lao về phía bạn.";
    } else if (slowCount > fastCount + 1) {
        return lang === 'en' ? "Wait with patience. This situation is <strong>slow-moving</strong>, likely taking months or becoming a permanent fixture in your life." : "Hãy kiên nhẫn chờ đợi. Tình huống này <strong>diễn chuyển chậm</strong>, có khả năng mất hàng tháng hoặc trở thành một phần cố định trong đời bạn.";
    } else {
        return lang === 'en' ? "Things are moving at a <strong>moderate pace</strong>. Expect a resolution or major shift within 2 to 4 weeks." : "Mọi thứ đang diễn chuyển với <strong>nhịp độ vừa phải</strong>. Chờ đợi một sự giải quyết hoặc thay đổi lớn trong vòng 2 đến 4 tuần.";
    }
}

function analyzeLiterals(cards, lang) {
    const card = cards[Math.floor(cards.length / 2)];
    if (lang === 'en') {
        return `Watch for physical signs related to <strong>${card.en.name}</strong>. This isn't a metaphor—someone or something matching this card's practical nature is entering your sphere. ${card.en.meaning || ""}`;
    } else {
        return `Chú ý các dấu hiệu vật lý liên quan đến <strong>${card.en.name}</strong>. Đây không phải ẩn dụ—ai đó hoặc điều gì đó mang bản chất thực tế của lá bài này đang bước vào cuộc sống của bạn.`;
    }
}

if (typeof module !== 'undefined' && module.exports) {
    module.exports = { interpretLenormandCombination, generateLenormandSynthesis, lenormandCombinations };
}

